import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline
import math

# Define the custom CUDA kernel for fused linear + mish + mish
fused_linear_mish_mish_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <math.h>

namespace {
    __device__ __forceinline__ float mish_activation(float x) {
        // Mish: x * tanh(softplus(x))
        // softplus(x) = log(1 + exp(x))
        float sp = log1pf(expf(x));
        return x * tanhf(sp);
    }
}

__global__ void fused_linear_mish_mish_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int batch_size,
    int in_features,
    int out_features
) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < batch_size && col < out_features) {
        float sum = 0.0f;

        // Compute dot product
        for (int k = 0; k < in_features; ++k) {
            sum += input[row * in_features + k] * weight[col * in_features + k];
        }

        // Add bias if provided
        if (bias != nullptr) {
            sum += bias[col];
        }

        // Apply Mish twice
        float result = mish_activation(sum);
        result = mish_activation(result);

        output[row * out_features + col] = result;
    }
}

torch::Tensor fused_linear_mish_mish_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias
) {
    int batch_size = input.size(0);
    int in_features = input.size(1);
    int out_features = weight.size(0);

    auto output = torch::empty({batch_size, out_features}, 
                              torch::TensorOptions()
                              .dtype(input.dtype())
                              .device(input.device()));

    // Simple block configuration
    const int BLOCK_SIZE = 16;
    dim3 block(BLOCK_SIZE, BLOCK_SIZE);
    dim3 grid(
        (out_features + block.x - 1) / block.x,
        (batch_size + block.y - 1) / block.y
    );

    fused_linear_mish_mish_kernel<<<grid, block>>>(
        input.data_ptr<float>(),
        weight.data_ptr<float>(),
        bias.defined() ? bias.data_ptr<float>() : nullptr,
        output.data_ptr<float>(),
        batch_size,
        in_features,
        out_features
    );

    return output;
}
"""

fused_linear_mish_mish_cpp_source = """
torch::Tensor fused_linear_mish_mish_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias
);
"""

# Compile the inline CUDA code
fused_linear_mish_mish = load_inline(
    name="fused_linear_mish_mish",
    cpp_sources=fused_linear_mish_mish_cpp_source,
    cuda_sources=fused_linear_mish_mish_source,
    functions=["fused_linear_mish_mish_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    """
    Optimized model with fused linear + mish + mish operation.
    """
    def __init__(self, in_features, out_features):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features

        # Initialize weights and bias
        self.weight = nn.Parameter(torch.empty(out_features, in_features))
        self.bias = nn.Parameter(torch.empty(out_features))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

    def forward(self, x):
        return fused_linear_mish_mish.fused_linear_mish_mish_cuda(x, self.weight, self.bias)

